/**
 * Unit Tests for RuleScoringNode
 *
 * Tests the lexical pattern matching, bounded aggregation, and scoring logic
 * for the EmailCategorizer workflow's rule-based classification stage.
 */

const RuleScoringNode = require('../../../src/workflows/EmailCategorizer/RuleScoringNode');

describe('RuleScoringNode', () => {
  let node;
  let mockInput;
  let mockConfig;

  beforeEach(() => {
    node = new RuleScoringNode();

    // Mock configuration with test rules
    mockConfig = {
      config: {
        processing_config: {
          top_level_categories: {
            financial: {
              description: 'Financial communications',
              subtypes: {
                receipt: {
                  rule_based_classification: {
                    high_confidence: [
                      {
                        field: 'subject',
                        operation: 'contains_any',
                        values: ['receipt', 'payment confirmation'],
                        weight: 12,
                      },
                    ],
                    medium_confidence: [
                      {
                        field: 'body',
                        operation: 'contains_any',
                        values: ['total', 'amount', 'charged'],
                        weight: 6,
                      },
                    ],
                    low_confidence: [
                      {
                        field: 'subject',
                        operation: 'contains_any',
                        values: ['purchase', 'order'],
                        weight: 3,
                      },
                    ],
                  },
                },
                invoice: {
                  rule_based_classification: {
                    high_confidence: [
                      {
                        field: 'subject',
                        operation: 'contains_any',
                        values: ['invoice'],
                        weight: 12,
                      },
                    ],
                  },
                },
              },
            },
            actionable: {
              description: 'Action-required emails',
              subtypes: {
                explicit_action: {
                  rule_based_classification: {
                    high_confidence: [
                      {
                        field: 'subject',
                        operation: 'starts_with',
                        values: ['TODO:', 'ACTION:', 'TASK:'],
                        weight: 15,
                      },
                    ],
                  },
                },
              },
            },
            test_regex: {
              description: 'Test regex patterns',
              subtypes: {
                regex_test: {
                  rule_based_classification: {
                    medium_confidence: [
                      {
                        field: 'body',
                        operation: 'regex_any',
                        values: ['\\$\\d+\\.\\d{2}', 'USD \\d+'],
                        weight: 8,
                      },
                    ],
                  },
                },
              },
            },
          },
        },
      },
      domain_sources: {},
    };

    // Mock $getWorkflowStaticData function
    global.$getWorkflowStaticData = jest.fn().mockReturnValue({
      email_categorizer_config: mockConfig,
    });
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('execute()', () => {
    it('should process emails with rule matching successfully', async () => {
      mockInput = {
        all: () => [
          {
            json: {
              gmail_id: 'test123',
              subject: 'Receipt for your purchase',
              body_text: 'Thank you for your purchase. Total: twenty-five dollars',
              candidate_scores: {
                financial: 0,
                actionable: 0,
              },
              pipeline_stage: 'initialize_candidates',
            },
          },
        ],
        first: () => ({ json: { gmail_id: 'test123' } }),
      };

      const result = await node.execute(mockInput);

      expect(result).toHaveLength(1);
      expect(result[0].json.pipeline_stage).toBe('rule_scoring');
      expect(result[0].json.candidate_scores.financial.score).toBe(21); // 12 + 6 + 3
      expect(result[0].json.rule_scoring_summary.total_rule_matches).toBe(3);
    });

    it('should handle emails with no rule matches', async () => {
      mockInput = {
        all: () => [
          {
            json: {
              gmail_id: 'test456',
              subject: 'Random email subject',
              body_text: 'This is just a random email with no patterns',
              candidate_scores: {
                financial: 0,
                actionable: 0,
              },
            },
          },
        ],
      };

      const result = await node.execute(mockInput);

      expect(result).toHaveLength(1);
      expect(result[0].json.candidate_scores.financial.score).toBe(0);
      expect(result[0].json.rule_scoring_summary.total_rule_matches).toBe(0);
    });

    it('should preserve existing scores from hard assertions', async () => {
      mockInput = {
        all: () => [
          {
            json: {
              gmail_id: 'test789',
              subject: 'Random subject',
              body_text: 'Random body',
              candidate_scores: {
                financial: 15, // Existing hard assertion score
                actionable: 0,
              },
            },
          },
        ],
      };

      const result = await node.execute(mockInput);

      expect(result).toHaveLength(1);
      expect(result[0].json.candidate_scores.financial.score).toBe(15); // Should preserve existing score
    });

    it('should handle multiple categories with matches', async () => {
      mockInput = {
        all: () => [
          {
            json: {
              gmail_id: 'test101',
              subject: 'TODO: Review receipt for meeting expenses',
              body_text: 'Please review the total amount charged',
              candidate_scores: {
                financial: 0,
                actionable: 0,
              },
            },
          },
        ],
      };

      const result = await node.execute(mockInput);

      expect(result).toHaveLength(1);
      expect(result[0].json.candidate_scores.financial.score).toBe(18); // receipt rules
      expect(result[0].json.candidate_scores.actionable.score).toBe(15); // TODO rule
      expect(result[0].json.rule_scoring_summary.categories_with_rules).toBe(2);
    });
  });

  describe('_scoreSubtype()', () => {
    const mockEmail = {
      subject: 'Receipt for your purchase',
      body_text: 'Thank you for your purchase. Total: $25.99',
    };

    it('should score high confidence patterns correctly', () => {
      const subtypeData = {
        rule_based_classification: {
          high_confidence: [
            {
              field: 'subject',
              operation: 'contains_any',
              values: ['receipt'],
              weight: 12,
            },
          ],
        },
      };

      const result = node._scoreSubtype(mockEmail, subtypeData, 'receipt');

      expect(result.score).toBe(12);
      expect(result.matches).toHaveLength(1);
      expect(result.matches[0].tier).toBe('high_confidence');
      expect(result.matches[0].matched_value).toBe('receipt');
    });

    it('should accumulate scores across confidence tiers', () => {
      const subtypeData = {
        rule_based_classification: {
          high_confidence: [
            {
              field: 'subject',
              operation: 'contains_any',
              values: ['receipt'],
              weight: 12,
            },
          ],
          medium_confidence: [
            {
              field: 'body',
              operation: 'contains_any',
              values: ['total'],
              weight: 6,
            },
          ],
        },
      };

      const result = node._scoreSubtype(mockEmail, subtypeData, 'receipt');

      expect(result.score).toBe(18); // 12 + 6
      expect(result.matches).toHaveLength(2);
    });

    it('should handle subtypes with no matches', () => {
      const subtypeData = {
        rule_based_classification: {
          high_confidence: [
            {
              field: 'subject',
              operation: 'contains_any',
              values: ['invoice'],
              weight: 12,
            },
          ],
        },
      };

      const result = node._scoreSubtype(mockEmail, subtypeData, 'invoice');

      expect(result.score).toBe(0);
      expect(result.matches).toHaveLength(0);
    });
  });

  describe('_evaluateRule()', () => {
    it('should match contains_any operation', () => {
      const rule = {
        field: 'subject',
        operation: 'contains_any',
        values: ['receipt', 'invoice'],
      };

      const result = node._evaluateRule(rule, 'receipt for purchase', '');

      expect(result.matched).toBe(true);
      expect(result.matchedValue).toBe('receipt');
    });

    it('should match starts_with operation', () => {
      const rule = {
        field: 'subject',
        operation: 'starts_with',
        values: ['TODO:', 'ACTION:'],
      };

      const result = node._evaluateRule(rule, 'todo: review documents', '');

      expect(result.matched).toBe(true);
      expect(result.matchedValue).toBe('TODO:');
    });

    it('should match ends_with operation', () => {
      const rule = {
        field: 'subject',
        operation: 'ends_with',
        values: ['?', '!'],
      };

      const result = node._evaluateRule(rule, 'what do you think?', '');

      expect(result.matched).toBe(true);
      expect(result.matchedValue).toBe('?');
    });

    it('should match regex_any operation', () => {
      const rule = {
        field: 'body',
        operation: 'regex_any',
        values: ['\\$\\d+\\.\\d{2}'],
      };

      const result = node._evaluateRule(rule, '', 'total cost is $25.99');

      expect(result.matched).toBe(true);
      expect(result.matchedValue).toBe('$25.99');
    });

    it('should handle invalid regex gracefully', () => {
      const rule = {
        field: 'body',
        operation: 'regex_any',
        values: ['[invalid regex'],
      };

      // Spy on console.log to verify error logging
      const consoleSpy = jest.spyOn(console, 'log').mockImplementation();

      const result = node._evaluateRule(rule, '', 'test content');

      expect(result.matched).toBe(false);
      expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('Invalid regex pattern'));

      consoleSpy.mockRestore();
    });

    it('should return false for no matches', () => {
      const rule = {
        field: 'subject',
        operation: 'contains_any',
        values: ['invoice', 'statement'],
      };

      const result = node._evaluateRule(rule, 'receipt for purchase', '');

      expect(result.matched).toBe(false);
      expect(result.matchedValue).toBe(null);
    });

    it('should handle unknown operations', () => {
      const rule = {
        field: 'subject',
        operation: 'unknown_operation',
        values: ['test'],
      };

      const consoleSpy = jest.spyOn(console, 'log').mockImplementation();

      const result = node._evaluateRule(rule, 'test subject', '');

      expect(result.matched).toBe(false);
      expect(consoleSpy).toHaveBeenCalledWith('Unknown rule operation: unknown_operation');

      consoleSpy.mockRestore();
    });
  });

  describe('_calculateBoundedAggregation()', () => {
    it('should use primary subtype score when only one subtype', () => {
      const subtypeScores = {
        receipt: { score: 15 },
      };

      const result = node._calculateBoundedAggregation(subtypeScores, 'financial');

      expect(result.totalScore).toBe(15);
      expect(result.breakdown).toBe('primary:receipt:15');
    });

    it('should apply dampening to tail subtypes', () => {
      const subtypeScores = {
        receipt: { score: 12 },
        invoice: { score: 10 },
        statement: { score: 8 },
      };

      const result = node._calculateBoundedAggregation(subtypeScores, 'financial');

      expect(result.totalScore).toBe(17.4); // 12 + (10 * 0.3) + (8 * 0.3) = 12 + 3 + 2.4
      expect(result.breakdown).toContain('primary:receipt:12');
      expect(result.breakdown).toContain('tail:5.4');
    });

    it('should handle empty subtype scores', () => {
      const subtypeScores = {};

      const result = node._calculateBoundedAggregation(subtypeScores, 'financial');

      expect(result.totalScore).toBe(0);
      expect(result.breakdown).toBe('no_subtypes');
    });

    it('should sort subtypes by score descending', () => {
      const subtypeScores = {
        invoice: { score: 8 }, // Should be tail
        receipt: { score: 15 }, // Should be primary
        statement: { score: 10 }, // Should be tail
      };

      const result = node._calculateBoundedAggregation(subtypeScores, 'financial');

      expect(result.totalScore).toBe(20.4); // 15 + (10 * 0.3) + (8 * 0.3) = 15 + 3 + 2.4
      expect(result.breakdown).toContain('primary:receipt:15');
    });
  });

  describe('Edge Cases and Error Handling', () => {
    it('should handle missing subject and body fields', async () => {
      mockInput = {
        all: () => [
          {
            json: {
              gmail_id: 'test_missing_fields',
              // No subject or body_text
              candidate_scores: {
                financial: 0,
              },
            },
          },
        ],
      };

      const result = await node.execute(mockInput);

      expect(result).toHaveLength(1);
      expect(result[0].json.candidate_scores.financial.score).toBe(0);
    });

    it('should handle missing configuration gracefully', async () => {
      global.$getWorkflowStaticData = jest.fn().mockReturnValue({});

      mockInput = {
        all: () => [
          {
            json: {
              gmail_id: 'test_no_config',
              subject: 'Test',
              candidate_scores: {},
            },
          },
        ],
      };

      await expect(node.execute(mockInput)).rejects.toThrow(
        'Email categorizer configuration not found in workflow static data'
      );
    });

    it('should handle empty input array', async () => {
      mockInput = {
        all: () => [],
        first: () => null,
      };

      const result = await node.execute(mockInput);

      expect(result).toHaveLength(0);
    });

    it('should handle missing rule_based_classification in subtypes', async () => {
      mockConfig.config.processing_config.top_level_categories.financial.subtypes.receipt = {
        description: 'Receipt without rules',
        // No rule_based_classification
      };

      global.$getWorkflowStaticData = jest.fn().mockReturnValue({
        email_categorizer_config: mockConfig,
      });

      mockInput = {
        all: () => [
          {
            json: {
              gmail_id: 'test_no_rules',
              subject: 'Receipt',
              body_text: 'Total: $25.99',
              candidate_scores: {
                financial: 0,
              },
            },
          },
        ],
      };

      const result = await node.execute(mockInput);

      expect(result).toHaveLength(1);
      expect(result[0].json.candidate_scores.financial.score).toBe(0);
    });
  });

  describe('Integration with Pipeline', () => {
    it('should preserve all original email data', async () => {
      const originalEmail = {
        gmail_id: 'integration_test',
        subject: 'Receipt for purchase',
        body_text: 'Total: $25.99',
        sent_at: '2025-08-24T10:00:00Z',
        from_addrs: { address: 'store@example.com' },
        candidate_scores: { financial: 0 },
        classification_session_id: 'session_123',
        hard_assertions_applied: [],
        pipeline_stage: 'initialize_candidates',
      };

      mockInput = {
        all: () => [{ json: originalEmail }],
      };

      const result = await node.execute(mockInput);

      expect(result[0].json.gmail_id).toBe(originalEmail.gmail_id);
      expect(result[0].json.sent_at).toBe(originalEmail.sent_at);
      expect(result[0].json.from_addrs).toEqual(originalEmail.from_addrs);
      expect(result[0].json.classification_session_id).toBe(originalEmail.classification_session_id);
      expect(result[0].json.pipeline_stage).toBe('rule_scoring');
    });

    it('should provide detailed scoring metadata for explainability', async () => {
      mockInput = {
        all: () => [
          {
            json: {
              gmail_id: 'explainability_test',
              subject: 'TODO: Review receipt',
              body_text: 'Total amount charged: $50.00',
              candidate_scores: {
                financial: 0,
                actionable: 0,
              },
            },
          },
        ],
      };

      const result = await node.execute(mockInput);
      const email = result[0].json;

      // Check detailed scoring metadata exists
      expect(email.subtype_scores).toBeDefined();
      expect(email.rule_matches).toBeDefined();
      expect(email.scoring_rationale).toBeDefined();
      expect(email.rule_scoring_summary).toBeDefined();

      // Check financial category details
      expect(email.subtype_scores.financial.receipt.score).toBe(18);
      expect(email.subtype_scores.financial.receipt.matches).toHaveLength(2);
      expect(email.scoring_rationale.financial[0]).toContain('Rule aggregation: primary:receipt:18');

      // Check actionable category details
      expect(email.subtype_scores.actionable.explicit_action.score).toBe(15);
      expect(email.subtype_scores.actionable.explicit_action.matches).toHaveLength(1);
    });

    it('should process real sample data from pipeline', async () => {
      // Load real sample data from the InitializeCandidatesNode output
      const path = require('path');
      const fs = require('fs');
      const sampleDataPath = path.join(
        __dirname,
        '../../../src/workflows/EmailCategorizer/sample-data/04-output-initialize-candidates.json'
      );

      let realInputData;
      try {
        const fileContent = fs.readFileSync(sampleDataPath, 'utf8');
        realInputData = JSON.parse(fileContent);
      } catch (error) {
        // Skip test if sample data file doesn't exist
        console.log('Skipping real data test - sample file not found:', error.message);
        return;
      }

      mockInput = {
        all: () => realInputData,
        first: () => realInputData[0],
      };

      const result = await node.execute(mockInput);

      // Validate basic structure
      expect(result).toHaveLength(realInputData.length);
      expect(result[0].json.pipeline_stage).toBe('rule_scoring');

      // Check that all emails have required scoring metadata
      for (const emailResult of result) {
        const email = emailResult.json;
        expect(email.candidate_scores).toBeDefined();
        expect(email.subtype_scores).toBeDefined();
        expect(email.rule_matches).toBeDefined();
        expect(email.scoring_rationale).toBeDefined();
        expect(email.rule_scoring_summary).toBeDefined();

        // Validate rule scoring summary structure
        expect(email.rule_scoring_summary.total_rule_matches).toBeGreaterThanOrEqual(0);
        expect(email.rule_scoring_summary.categories_with_rules).toBeGreaterThanOrEqual(0);
        expect(email.rule_scoring_summary.highest_rule_score).toBeGreaterThanOrEqual(0);
        expect(email.rule_scoring_summary.scoring_timestamp).toBeDefined();
      }

      // Validate that at least some emails got rule matches
      const totalMatches = result.reduce(
        (sum, emailResult) => sum + emailResult.json.rule_scoring_summary.total_rule_matches,
        0
      );
      expect(totalMatches).toBeGreaterThan(0);

      // Check detailed analysis for first email with matches
      const emailWithMatches = result.find((r) => r.json.rule_scoring_summary.total_rule_matches > 0);
      if (emailWithMatches) {
        const email = emailWithMatches.json;

        // Validate candidate scores structure
        for (const scoreObj of Object.values(email.candidate_scores)) {
          expect(scoreObj).toHaveProperty('score');
          expect(scoreObj).toHaveProperty('confidence');
          expect(scoreObj).toHaveProperty('scoring_components');
          expect(scoreObj).toHaveProperty('rationale');
          expect(scoreObj).toHaveProperty('selected_subtype_id');
          expect(scoreObj).toHaveProperty('decision');

          if (scoreObj.score > 0) {
            expect(scoreObj.scoring_components.rule_matches).toBeDefined();
            expect(scoreObj.scoring_components.total_rule_matches).toBeGreaterThan(0);
          }
        }
      }
    });
  });
});

